fn writeReplyMessage(ctx: *Context, msg_type: protocol.MessageType, message: []const u8) CmdError!void {
    if (ctx.reply_fd) |fd| {
        protocol.sendMessage(fd, msg_type, message) catch return CmdError.CommandFailed;
        return;
    }

    const target_fd: std.c.fd_t = switch (msg_type) {
        .error_msg => 2,
        else => 1,
    };
    _ = std.c.write(target_fd, message.ptr, message.len);
}

fn writeOutput(ctx: *Context, comptime fmt: []const u8, args: anytype) CmdError!void {
    var buf: [1024]u8 = undefined;
    const message = std.fmt.bufPrint(&buf, fmt, args) catch return CmdError.CommandFailed;
    try writeReplyMessage(ctx, .output, message);
}

/// Send clipboard data to all clients attached to the session via OSC 52.
fn sendOsc52Clipboard(ctx: *Context, data: []const u8) void {
    const session = ctx.session orelse return;
    const osc52 = clipboard_mod.Clipboard.encodeOsc52Set(ctx.allocator, data) catch return;
    defer ctx.allocator.free(osc52);
    for (ctx.server.clients.items) |client| {
        if (client.session == session and client.fd >= 0) {
            protocol.sendMessage(client.fd, .output, osc52) catch {};
        }
    }
}

fn spawnWindowPane(alloc: std.mem.Allocator, shell: [:0]const u8, sx: u32, sy: u32) CmdError!*Pane {
    const pane = Pane.init(alloc, sx, sy) catch return CmdError.OutOfMemory;
    errdefer pane.deinit();

    var pty = Pty.openPty() catch return CmdError.CommandFailed;
    pty.forkExec(shell, null) catch return CmdError.CommandFailed;
    pty.resize(@intCast(sx), @intCast(sy));
    pane.fd = pty.master_fd;
    pane.pid = pty.pid;
    return pane;
}

fn parseTargetWindow(args: []const []const u8) ?u32 {
    var i: usize = 0;
    while (i < args.len) : (i += 1) {
        if (!std.mem.eql(u8, args[i], "-t") or i + 1 >= args.len) continue;
        i += 1;
        const target = args[i];
        if (target.len >= 2 and target[0] == ':') {
            return std.fmt.parseInt(u32, target[1..], 10) catch null;
        }
        return std.fmt.parseInt(u32, target, 10) catch null;
    }
    return null;
}

/// Resolved target from tmux target syntax.
const ResolvedTarget = struct {
    session: ?*Session = null,
    window: ?*Window = null,
    pane: ?*Pane = null,
};

/// Resolve a tmux-style target string: [session:][window][.pane]
/// Supports:
///   - Session by name or `$` (last)
///   - Window by index, name, `!` (last), `+` (next), `-` (prev)
///   - Pane by index, `%id`, `!` (last), `+` (next), `-` (prev)
fn resolveTarget(server: *Server, current: *const Context, target: []const u8) ResolvedTarget {
    var result = ResolvedTarget{
        .session = current.session,
        .window = current.window,
        .pane = current.pane,
    };
    if (target.len == 0) return result;

    var session_part: ?[]const u8 = null;
    var window_part: ?[]const u8 = null;
    var pane_part: ?[]const u8 = null;

    // Split on ':' for session:window.pane
    var rest = target;
    if (std.mem.indexOfScalar(u8, rest, ':')) |colon| {
        session_part = rest[0..colon];
        rest = rest[colon + 1 ..];
    }
    // Split on '.' for window.pane
    if (std.mem.indexOfScalar(u8, rest, '.')) |dot| {
        window_part = rest[0..dot];
        pane_part = rest[dot + 1 ..];
    } else if (rest.len > 0) {
        window_part = rest;
    }

    // Resolve session
    if (session_part) |sp| {
        if (sp.len > 0) {
            result.session = resolveSessionToken(server, current.session, sp);
        }
    }

    const session = result.session orelse return result;

    // Resolve window
    if (window_part) |wp| {
        if (wp.len > 0) {
            result.window = resolveWindowToken(session, wp);
        }
    }

    const window = result.window orelse return result;

    // Resolve pane
    if (pane_part) |pp| {
        if (pp.len > 0) {
            result.pane = resolvePaneToken(window, pp);
        }
    }

    return result;
}

fn resolveSessionToken(server: *Server, current: ?*Session, token: []const u8) ?*Session {
    if (std.mem.eql(u8, token, "$")) {
        // Last session
        return if (server.sessions.items.len > 0) server.sessions.items[server.sessions.items.len - 1] else null;
    }
    // Try by name
    if (server.findSession(token)) |s| return s;
    // Try by id ($N)
    if (token.len > 1 and token[0] == '$') {
        const id = std.fmt.parseInt(u32, token[1..], 10) catch return current;
        for (server.sessions.items) |s| {
            if (s.id == id) return s;
        }
    }
    return current;
}

fn resolveWindowToken(session: *Session, token: []const u8) ?*Window {
    if (std.mem.eql(u8, token, "!")) {
        return session.last_window;
    }
    if (std.mem.eql(u8, token, "+")) {
        if (session.active_window) |aw| {
            for (session.windows.items, 0..) |w, i| {
                if (w == aw) return session.windows.items[(i + 1) % session.windows.items.len];
            }
        }
        return session.active_window;
    }
    if (std.mem.eql(u8, token, "-")) {
        if (session.active_window) |aw| {
            for (session.windows.items, 0..) |w, i| {
                if (w == aw) return session.windows.items[if (i == 0) session.windows.items.len - 1 else i - 1];
            }
        }
        return session.active_window;
    }
    // Try by index (base-index adjusted)
    if (std.fmt.parseInt(u32, token, 10) catch null) |num| {
        return session.findWindowByNumber(num);
    }
    // Try by name
    for (session.windows.items) |w| {
        if (std.mem.eql(u8, w.name, token)) return w;
    }
    return session.active_window;
}

fn resolvePaneToken(window: *Window, token: []const u8) ?*Pane {
    if (std.mem.eql(u8, token, "!")) {
        return window.last_pane;
    }
    if (std.mem.eql(u8, token, "+") or std.mem.eql(u8, token, ".+")) {
        if (window.active_pane) |ap| {
            for (window.panes.items, 0..) |p, i| {
                if (p == ap) return window.panes.items[(i + 1) % window.panes.items.len];
            }
        }
        return window.active_pane;
    }
    if (std.mem.eql(u8, token, "-") or std.mem.eql(u8, token, ".-")) {
        if (window.active_pane) |ap| {
            for (window.panes.items, 0..) |p, i| {
                if (p == ap) return window.panes.items[if (i == 0) window.panes.items.len - 1 else i - 1];
            }
        }
        return window.active_pane;
    }
    // %N pane id
    if (token.len >= 2 and token[0] == '%') {
        const id = std.fmt.parseInt(u32, token[1..], 10) catch return window.active_pane;
        for (window.panes.items) |p| {
            if (p.id == id) return p;
        }
        return null;
    }
    // Numeric index
    if (std.fmt.parseInt(usize, token, 10) catch null) |idx| {
        if (idx < window.panes.items.len) return window.panes.items[idx];
    }
    return window.active_pane;
}

/// Parse -t from args and resolve to session/window/pane, updating ctx.
fn resolveTargetFromArgs(ctx: *Context, args: []const []const u8) void {
    const target_str = parseNamedOption(args, "-t") orelse return;
    const resolved = resolveTarget(ctx.server, ctx, target_str);
    if (resolved.session) |s| ctx.session = s;
    if (resolved.window) |w| ctx.window = w;
    if (resolved.pane) |p| ctx.pane = p;
}

fn defaultShell(session: ?*Session) [:0]const u8 {
    if (session) |s| return s.options.default_shell;
    return "/bin/sh";
}

fn defaultShellFromContext(ctx: *const Context) [:0]const u8 {
    if (ctx.session) |s| return s.options.default_shell;
    if (ctx.server.global_default_shell) |shell| return shell;
    return "/bin/sh";
}

/// Get terminal dimensions from context: active window > client > 80x24.
fn terminalSize(ctx: *const Context) struct { cols: u32, rows: u32 } {
    if (ctx.session) |s| {
        if (s.active_window) |w| return .{ .cols = w.sx, .rows = w.sy };
    }
    if (ctx.client_index) |ci| {
        if (ci < ctx.server.clients.items.len) {
            const client = &ctx.server.clients.items[ci];
            return .{ .cols = client.cols, .rows = client.rows };
        }
    }
    return .{ .cols = 80, .rows = 24 };
}

/// Build a FormatContext from the current command context.
fn makeFormatContext(ctx: *const Context) format_mod.FormatContext {
    var fc = format_mod.FormatContext{};
    if (ctx.session) |s| {
        fc.session_name = s.name;
        fc.session_id = s.id;
        if (s.active_window) |w| {
            fc.window_name = w.name;
            for (s.windows.items, 0..) |win, idx| {
                if (win == w) {
                    fc.window_index = s.options.base_index + @as(u32, @intCast(idx));
                    fc.window_active = true;
                    break;
                }
            }
            if (w.active_pane) |p| {
                for (w.panes.items, 0..) |pane, idx| {
                    if (pane == p) {
                        fc.pane_index = @intCast(idx);
                        break;
                    }
                }
                fc.pane_pid = p.pid;
            }
        }
    }
    return fc;
}

