fn cmdRunShell(ctx: *Context, args: []const []const u8) CmdError!void {
    var background = false;
    var is_tmux_command = false;

    var i: usize = 0;
    while (i < args.len and args[i].len > 0 and args[i][0] == '-') : (i += 1) {
