const std = @import("std");
const bindings = @import("bindings.zig");
const Modifiers = bindings.Modifiers;

pub const KeyResult = struct {
    key: u21,
    mods: Modifiers,
};

/// Parse a tmux key string into a key code and modifiers.
/// Supports: C-b, M-a, S-F1, C-M-a, Enter, Space, F1-F12, Up/Down/Left/Right, etc.
pub fn stringToKey(s: []const u8) ?KeyResult {
    if (s.len == 0) return null;

    var remaining = s;
    var mods = Modifiers{};

    // Parse modifier prefixes: C-, M-, S-
    while (remaining.len >= 2 and remaining[1] == '-') {
        switch (remaining[0]) {
            'C' => mods.ctrl = true,
            'M' => mods.meta = true,
            'S' => mods.shift = true,
            else => break,
        }
        remaining = remaining[2..];
    }

    // Special key names
    const special_keys = [_]struct { name: []const u8, key: u21 }{
        .{ .name = "Enter", .key = '\r' },
        .{ .name = "Return", .key = '\r' },
        .{ .name = "Escape", .key = 0x1b },
        .{ .name = "Space", .key = ' ' },
        .{ .name = "Tab", .key = '\t' },
        .{ .name = "BSpace", .key = 0x7f },
        .{ .name = "Up", .key = 0x100 },
        .{ .name = "Down", .key = 0x101 },
        .{ .name = "Left", .key = 0x102 },
        .{ .name = "Right", .key = 0x103 },
        .{ .name = "Home", .key = 0x104 },
        .{ .name = "End", .key = 0x105 },
        .{ .name = "IC", .key = 0x106 },
        .{ .name = "Insert", .key = 0x106 },
        .{ .name = "DC", .key = 0x107 },
        .{ .name = "Delete", .key = 0x107 },
        .{ .name = "PgUp", .key = 0x108 },
        .{ .name = "PageUp", .key = 0x108 },
        .{ .name = "PgDn", .key = 0x109 },
        .{ .name = "PageDown", .key = 0x109 },
        .{ .name = "F1", .key = 0x110 },
        .{ .name = "F2", .key = 0x111 },
        .{ .name = "F3", .key = 0x112 },
        .{ .name = "F4", .key = 0x113 },
        .{ .name = "F5", .key = 0x114 },
        .{ .name = "F6", .key = 0x115 },
        .{ .name = "F7", .key = 0x116 },
        .{ .name = "F8", .key = 0x117 },
        .{ .name = "F9", .key = 0x118 },
        .{ .name = "F10", .key = 0x119 },
        .{ .name = "F11", .key = 0x11a },
        .{ .name = "F12", .key = 0x11b },
    };

    for (special_keys) |sk| {
        if (std.ascii.eqlIgnoreCase(remaining, sk.name)) {
            return .{ .key = sk.key, .mods = mods };
        }
    }

    // Single character
    if (remaining.len == 1) {
        return .{ .key = remaining[0], .mods = mods };
    }

    return null;
